use std::collections::HashMap;
use std::io::{self, Read};

const PI: f64 = 3.1415926535;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Comp {
    LT,
    EQ,
    GT,
}

fn realcompare(a: f64, b: f64) -> Comp {
    let scale = a.abs().max(b.abs());
    if scale == 0.0 {
        return Comp::EQ;
    }
    let eps = 0.5e-5 * scale;
    let diff = a - b;
    if diff > eps {
        Comp::GT
    } else if diff < -eps {
        Comp::LT
    } else {
        Comp::EQ
    }
}

#[derive(Debug, Clone)]
enum JsonValue {
    Null,
    Bool(bool),
    Num(f64),
    Str(String),
    Arr(Vec<JsonValue>),
    Obj(HashMap<String, JsonValue>),
}

struct Parser<'a> {
    s: &'a [u8],
    i: usize,
}

impl<'a> Parser<'a> {
    fn new(s: &'a str) -> Self {
        Self { s: s.as_bytes(), i: 0 }
    }

    fn parse(mut self) -> Result<JsonValue, String> {
        let v = self.parse_value()?;
        self.skip_ws();
        if self.i != self.s.len() {
            return Err("trailing characters".into());
        }
        Ok(v)
    }

    fn skip_ws(&mut self) {
        while self.i < self.s.len() && matches!(self.s[self.i], b' ' | b'\n' | b'\r' | b'\t') {
            self.i += 1;
        }
    }

    fn peek(&mut self) -> Option<u8> {
        self.skip_ws();
        self.s.get(self.i).copied()
    }

    fn bump(&mut self) -> Option<u8> {
        let ch = self.s.get(self.i).copied();
        if ch.is_some() {
            self.i += 1;
        }
        ch
    }

    fn expect(&mut self, expected: u8) -> Result<(), String> {
        self.skip_ws();
        match self.bump() {
            Some(c) if c == expected => Ok(()),
            _ => Err(format!("expected '{}'", expected as char)),
        }
    }

    fn parse_value(&mut self) -> Result<JsonValue, String> {
        self.skip_ws();
        match self.peek() {
            Some(b'{') => self.parse_object(),
            Some(b'[') => self.parse_array(),
            Some(b'"') => self.parse_string().map(JsonValue::Str),
            Some(b't') => {
                self.expect_bytes(b"true")?;
                Ok(JsonValue::Bool(true))
            }
            Some(b'f') => {
                self.expect_bytes(b"false")?;
                Ok(JsonValue::Bool(false))
            }
            Some(b'n') => {
                self.expect_bytes(b"null")?;
                Ok(JsonValue::Null)
            }
            Some(b'-') | Some(b'0'..=b'9') => self.parse_number(),
            _ => Err("unexpected character".into()),
        }
    }

    fn expect_bytes(&mut self, expected: &[u8]) -> Result<(), String> {
        self.skip_ws();
        if self.s.get(self.i..self.i + expected.len()) == Some(expected) {
            self.i += expected.len();
            Ok(())
        } else {
            Err("unexpected token".into())
        }
    }

    fn parse_string(&mut self) -> Result<String, String> {
        self.skip_ws();
        if self.bump() != Some(b'"') {
            return Err("expected string".into());
        }
        let mut out = String::new();
        while let Some(c) = self.bump() {
            match c {
                b'"' => return Ok(out),
                b'\\' => {
                    let esc = self.bump().ok_or_else(|| "unterminated escape".to_string())?;
                    match esc {
                        b'"' => out.push('"'),
                        b'\\' => out.push('\\'),
                        b'/' => out.push('/'),
                        b'b' => out.push('\u{0008}'),
                        b'f' => out.push('\u{000C}'),
                        b'n' => out.push('\n'),
                        b'r' => out.push('\r'),
                        b't' => out.push('\t'),
                        b'u' => {
                            let code = self.parse_hex4()?;
                            if let Some(ch) = char::from_u32(code) {
                                out.push(ch);
                            } else {
                                return Err("invalid unicode escape".into());
                            }
                        }
                        _ => return Err("invalid escape".into()),
                    }
                }
                _ => out.push(c as char),
            }
        }
        Err("unterminated string".into())
    }

    fn parse_hex4(&mut self) -> Result<u32, String> {
        let mut code = 0u32;
        for _ in 0..4 {
            let c = self.bump().ok_or_else(|| "unterminated unicode escape".to_string())?;
            code <<= 4;
            code |= match c {
                b'0'..=b'9' => (c - b'0') as u32,
                b'a'..=b'f' => (10 + c - b'a') as u32,
                b'A'..=b'F' => (10 + c - b'A') as u32,
                _ => return Err("invalid unicode escape".into()),
            };
        }
        Ok(code)
    }

    fn parse_number(&mut self) -> Result<JsonValue, String> {
        self.skip_ws();
        let start = self.i;
        if self.peek() == Some(b'-') {
            self.i += 1;
        }
        self.consume_digits();
        if self.peek() == Some(b'.') {
            self.i += 1;
            self.consume_digits();
        }
        if matches!(self.peek(), Some(b'e') | Some(b'E')) {
            self.i += 1;
            if matches!(self.peek(), Some(b'+') | Some(b'-')) {
                self.i += 1;
            }
            self.consume_digits();
        }
        let s = std::str::from_utf8(&self.s[start..self.i]).map_err(|_| "invalid number".to_string())?;
        let n = s.parse::<f64>().map_err(|_| "invalid number".to_string())?;
        Ok(JsonValue::Num(n))
    }

    fn consume_digits(&mut self) {
        while matches!(self.peek(), Some(b'0'..=b'9')) {
            self.i += 1;
        }
    }

    fn parse_array(&mut self) -> Result<JsonValue, String> {
        self.expect(b'[')?;
        let mut items = Vec::new();
        loop {
            self.skip_ws();
            if self.peek() == Some(b']') {
                self.i += 1;
                break;
            }
            items.push(self.parse_value()?);
            self.skip_ws();
            match self.peek() {
                Some(b',') => {
                    self.i += 1;
                }
                Some(b']') => {
                    self.i += 1;
                    break;
                }
                _ => return Err("expected ',' or ']'".into()),
            }
        }
        Ok(JsonValue::Arr(items))
    }

    fn parse_object(&mut self) -> Result<JsonValue, String> {
        self.expect(b'{')?;
        let mut map = HashMap::new();
        loop {
            self.skip_ws();
            if self.peek() == Some(b'}') {
                self.i += 1;
                break;
            }
            let key = self.parse_string()?;
            self.skip_ws();
            self.expect(b':')?;
            let value = self.parse_value()?;
            map.insert(key, value);
            self.skip_ws();
            match self.peek() {
                Some(b',') => {
                    self.i += 1;
                }
                Some(b'}') => {
                    self.i += 1;
                    break;
                }
                _ => return Err("expected ',' or '}'".into()),
            }
        }
        Ok(JsonValue::Obj(map))
    }
}

fn as_obj<'a>(v: &'a JsonValue) -> &'a HashMap<String, JsonValue> {
    match v {
        JsonValue::Obj(m) => m,
        _ => panic!("expected object"),
    }
}

fn as_arr<'a>(v: &'a JsonValue) -> &'a [JsonValue] {
    match v {
        JsonValue::Arr(a) => a,
        _ => panic!("expected array"),
    }
}

fn as_bool(v: &JsonValue) -> bool {
    match v {
        JsonValue::Bool(b) => *b,
        _ => panic!("expected bool"),
    }
}

fn as_num(v: &JsonValue) -> f64 {
    match v {
        JsonValue::Num(n) => *n,
        _ => panic!("expected number"),
    }
}

fn as_str(v: &JsonValue) -> &str {
    match v {
        JsonValue::Str(s) => s,
        _ => panic!("expected string"),
    }
}

fn get_field<'a>(obj: &'a HashMap<String, JsonValue>, key: &str) -> &'a JsonValue {
    obj.get(key).unwrap_or_else(|| panic!("missing field {}", key))
}

fn dist2(ax: f64, ay: f64, bx: f64, by: f64) -> f64 {
    let dx = ax - bx;
    let dy = ay - by;
    dx * dx + dy * dy
}

fn quad(x: f64, y: f64) -> usize {
    if realcompare(x, 0.0) != Comp::LT && realcompare(y, 0.0) != Comp::LT {
        0
    } else if realcompare(x, 0.0) == Comp::LT && realcompare(y, 0.0) != Comp::LT {
        1
    } else if realcompare(x, 0.0) != Comp::GT && realcompare(y, 0.0) == Comp::LT {
        2
    } else {
        3
    }
}

fn triangle_area(ax: f64, ay: f64, bx: f64, by: f64, cx: f64, cy: f64) -> f64 {
    ((bx - ax) * (cy - ay) - (by - ay) * (cx - ax)).abs() * 0.5
}

fn angle_at(ax: f64, ay: f64, bx: f64, by: f64, cx: f64, cy: f64) -> Option<f64> {
    let ux = ax - bx;
    let uy = ay - by;
    let vx = cx - bx;
    let vy = cy - by;
    if realcompare(ux, 0.0) == Comp::EQ && realcompare(uy, 0.0) == Comp::EQ {
        return None;
    }
    if realcompare(vx, 0.0) == Comp::EQ && realcompare(vy, 0.0) == Comp::EQ {
        return None;
    }
    let dot = ux * vx + uy * vy;
    let cross = ux * vy - uy * vx;
    Some(cross.abs().atan2(dot))
}

fn circle_contains_three(ax: f64, ay: f64, bx: f64, by: f64, cx: f64, cy: f64, radius: f64) -> bool {
    let a2 = dist2(bx, by, cx, cy);
    let b2 = dist2(ax, ay, cx, cy);
    let c2 = dist2(ax, ay, bx, by);
    let mut sides = [a2, b2, c2];
    sides.sort_by(|l, r| l.partial_cmp(r).unwrap());
    let s1 = sides[0];
    let s2 = sides[1];
    let s3 = sides[2];
    let two_r2 = (2.0 * radius) * (2.0 * radius);
    if realcompare(s3, two_r2) == Comp::GT {
        return false;
    }
    if realcompare(s3, s1 + s2) != Comp::LT {
        return true;
    }
    let cross = (bx - ax) * (cy - ay) - (by - ay) * (cx - ax);
    let cross2 = cross * cross;
    if realcompare(cross2, 0.0) == Comp::EQ {
        return true;
    }
    let circum_r2 = (a2 * b2 * c2) / (4.0 * cross2);
    realcompare(circum_r2, radius * radius) != Comp::GT
}

fn solve(input: JsonValue) -> JsonValue {
    let root = as_obj(&input);
    let numpoints = as_num(get_field(root, "numpoints")) as usize;
    let x_vals = as_arr(get_field(root, "x"))
        .iter()
        .map(as_num)
        .collect::<Vec<_>>();
    let y_vals = as_arr(get_field(root, "y"))
        .iter()
        .map(as_num)
        .collect::<Vec<_>>();
    let params = as_obj(get_field(root, "parameters"));
    let lcm_rows = as_arr(get_field(root, "lcm"));
    let pum_diag = as_arr(get_field(root, "pum_diag"))
        .iter()
        .map(as_bool)
        .collect::<Vec<_>>();

    let length1 = as_num(get_field(params, "LENGTH1"));
    let radius1 = as_num(get_field(params, "RADIUS1"));
    let epsilon = as_num(get_field(params, "EPSILON"));
    let area1 = as_num(get_field(params, "AREA1"));
    let q_pts = as_num(get_field(params, "Q_PTS")) as usize;
    let quads = as_num(get_field(params, "QUADS")) as usize;
    let dist = as_num(get_field(params, "DIST"));
    let n_pts = as_num(get_field(params, "N_PTS")) as usize;
    let k_pts = as_num(get_field(params, "K_PTS")) as usize;
    let a_pts = as_num(get_field(params, "A_PTS")) as usize;
    let b_pts = as_num(get_field(params, "B_PTS")) as usize;
    let c_pts = as_num(get_field(params, "C_PTS")) as usize;
    let d_pts = as_num(get_field(params, "D_PTS")) as usize;
    let e_pts = as_num(get_field(params, "E_PTS")) as usize;
    let f_pts = as_num(get_field(params, "F_PTS")) as usize;
    let g_pts = as_num(get_field(params, "G_PTS")) as usize;
    let length2 = as_num(get_field(params, "LENGTH2"));
    let radius2 = as_num(get_field(params, "RADIUS2"));
    let area2 = as_num(get_field(params, "AREA2"));

    let length1_ok = realcompare(length1, 0.0) != Comp::LT;
    let radius1_ok = realcompare(radius1, 0.0) != Comp::LT;
    let epsilon_ok = realcompare(epsilon, 0.0) != Comp::LT && realcompare(epsilon, PI) == Comp::LT;
    let area1_ok = realcompare(area1, 0.0) != Comp::LT;
    let q_pts_ok = q_pts >= 2 && q_pts <= numpoints;
    let quads_ok = (1..=3).contains(&quads);
    let dist_ok = realcompare(dist, 0.0) != Comp::LT;
    let n_pts_ok = n_pts >= 3 && n_pts <= numpoints;
    let k_pts_ok = k_pts >= 1 && k_pts <= numpoints.saturating_sub(2);
    let a_pts_ok = a_pts >= 1 && b_pts >= 1 && a_pts + b_pts <= numpoints.saturating_sub(3);
    let c_pts_ok = c_pts >= 1 && d_pts >= 1 && c_pts + d_pts <= numpoints.saturating_sub(3);
    let e_pts_ok = e_pts >= 1 && f_pts >= 1 && e_pts + f_pts <= numpoints.saturating_sub(3);
    let g_pts_ok = g_pts >= 1 && g_pts <= numpoints.saturating_sub(2);
    let length2_ok = realcompare(length2, 0.0) != Comp::LT;
    let radius2_ok = realcompare(radius2, 0.0) != Comp::LT;
    let area2_ok = realcompare(area2, 0.0) != Comp::LT;

    let mut cmv = vec![false; 15];

    // LIC 1
    cmv[0] = length1_ok && (0..numpoints.saturating_sub(1)).any(|i| {
        let d = dist2(x_vals[i], y_vals[i], x_vals[i + 1], y_vals[i + 1]).sqrt();
        realcompare(d, length1) == Comp::GT
    });

    // LIC 2
    cmv[1] = radius1_ok && if numpoints < 3 {
        false
    } else {
        (0..=numpoints - 3).any(|i| !circle_contains_three(
            x_vals[i],
            y_vals[i],
            x_vals[i + 1],
            y_vals[i + 1],
            x_vals[i + 2],
            y_vals[i + 2],
            radius1,
        ))
    };

    // LIC 3
    cmv[2] = epsilon_ok && if numpoints < 3 {
        false
    } else {
        (0..=numpoints - 3).any(|i| {
            match angle_at(
                x_vals[i],
                y_vals[i],
                x_vals[i + 1],
                y_vals[i + 1],
                x_vals[i + 2],
                y_vals[i + 2],
            ) {
                Some(theta) => realcompare(theta, PI - epsilon) == Comp::LT,
                None => false,
            }
        })
    };

    // LIC 4
    cmv[3] = area1_ok && if numpoints < 3 {
        false
    } else {
        (0..=numpoints - 3).any(|i| {
            realcompare(
                triangle_area(
                    x_vals[i],
                    y_vals[i],
                    x_vals[i + 1],
                    y_vals[i + 1],
                    x_vals[i + 2],
                    y_vals[i + 2],
                ),
                area1,
            ) == Comp::GT
        })
    };

    // LIC 5
    cmv[4] = q_pts_ok && quads_ok && if numpoints < q_pts {
        false
    } else {
        (0..=numpoints - q_pts).any(|i| {
            let mut seen = [false; 4];
            let mut count = 0usize;
            for j in i..i + q_pts {
                let q = quad(x_vals[j], y_vals[j]);
                if !seen[q] {
                    seen[q] = true;
                    count += 1;
                }
            }
            count > quads
        })
    };

    // LIC 6
    cmv[5] = (0..numpoints.saturating_sub(1)).any(|i| {
        realcompare(x_vals[i + 1], x_vals[i]) == Comp::LT
    });

    // LIC 7
    cmv[6] = dist_ok && n_pts_ok && if numpoints < n_pts || n_pts < 3 {
        false
    } else {
        (0..=numpoints - n_pts).any(|i| {
            let x1 = x_vals[i];
            let y1 = y_vals[i];
            let x2 = x_vals[i + n_pts - 1];
            let y2 = y_vals[i + n_pts - 1];
            if realcompare(x1, x2) == Comp::EQ && realcompare(y1, y2) == Comp::EQ {
                (i..i + n_pts).any(|k| {
                    let d = dist2(x1, y1, x_vals[k], y_vals[k]).sqrt();
                    realcompare(d, dist) == Comp::GT
                })
            } else {
                let denom = dist2(x1, y1, x2, y2).sqrt();
                (i + 1..i + n_pts - 1).any(|k| {
                    let numer = ((x_vals[k] - x1) * (y2 - y1) - (y_vals[k] - y1) * (x2 - x1)).abs();
                    let d = numer / denom;
                    realcompare(d, dist) == Comp::GT
                })
            }
        })
    };

    // LIC 8
    cmv[7] = length1_ok && k_pts_ok && if numpoints < k_pts + 2 {
        false
    } else {
        (0..=numpoints - k_pts - 2).any(|i| {
            let d = dist2(x_vals[i], y_vals[i], x_vals[i + k_pts + 1], y_vals[i + k_pts + 1]).sqrt();
            realcompare(d, length1) == Comp::GT
        })
    };

    // LIC 9
    cmv[8] = radius1_ok && a_pts_ok && if numpoints < a_pts + b_pts + 3 {
        false
    } else {
        (0..=numpoints - a_pts - b_pts - 3).any(|i| {
            !circle_contains_three(
                x_vals[i],
                y_vals[i],
                x_vals[i + a_pts + 1],
                y_vals[i + a_pts + 1],
                x_vals[i + a_pts + b_pts + 2],
                y_vals[i + a_pts + b_pts + 2],
                radius1,
            )
        })
    };

    // LIC 10
    cmv[9] = epsilon_ok && c_pts_ok && if numpoints < c_pts + d_pts + 3 {
        false
    } else {
        (0..=numpoints - c_pts - d_pts - 3).any(|i| {
            match angle_at(
                x_vals[i],
                y_vals[i],
                x_vals[i + c_pts + 1],
                y_vals[i + c_pts + 1],
                x_vals[i + c_pts + d_pts + 2],
                y_vals[i + c_pts + d_pts + 2],
            ) {
                Some(theta) => realcompare(theta, PI - epsilon) == Comp::LT,
                None => false,
            }
        })
    };

    // LIC 11
    cmv[10] = area1_ok && e_pts_ok && if numpoints < e_pts + f_pts + 3 {
        false
    } else {
        (0..=numpoints - e_pts - f_pts - 3).any(|i| {
            realcompare(
                triangle_area(
                    x_vals[i],
                    y_vals[i],
                    x_vals[i + e_pts + 1],
                    y_vals[i + e_pts + 1],
                    x_vals[i + e_pts + f_pts + 2],
                    y_vals[i + e_pts + f_pts + 2],
                ),
                area1,
            ) == Comp::GT
        })
    };

    // LIC 12
    cmv[11] = g_pts_ok && if numpoints < g_pts + 2 {
        false
    } else {
        (0..=numpoints - g_pts - 2).any(|i| {
            realcompare(x_vals[i + g_pts + 1], x_vals[i]) == Comp::LT
        })
    };

    // LIC 13
    cmv[12] = length1_ok && length2_ok && k_pts_ok && if numpoints < k_pts + 2 {
        false
    } else {
        let mut gt = false;
        let mut lt = false;
        for i in 0..=numpoints - k_pts - 2 {
            let d = dist2(x_vals[i], y_vals[i], x_vals[i + k_pts + 1], y_vals[i + k_pts + 1]).sqrt();
            if realcompare(d, length1) == Comp::GT {
                gt = true;
            }
            if realcompare(d, length2) == Comp::LT {
                lt = true;
            }
            if gt && lt {
                break;
            }
        }
        gt && lt
    };

    // LIC 14
    cmv[13] = radius1_ok && radius2_ok && a_pts_ok && if numpoints < a_pts + b_pts + 3 {
        false
    } else {
        let mut not_fit_r1 = false;
        let mut fit_r2 = false;
        for i in 0..=numpoints - a_pts - b_pts - 3 {
            let fits1 = circle_contains_three(
                x_vals[i],
                y_vals[i],
                x_vals[i + a_pts + 1],
                y_vals[i + a_pts + 1],
                x_vals[i + a_pts + b_pts + 2],
                y_vals[i + a_pts + b_pts + 2],
                radius1,
            );
            let fits2 = circle_contains_three(
                x_vals[i],
                y_vals[i],
                x_vals[i + a_pts + 1],
                y_vals[i + a_pts + 1],
                x_vals[i + a_pts + b_pts + 2],
                y_vals[i + a_pts + b_pts + 2],
                radius2,
            );
            if !fits1 {
                not_fit_r1 = true;
            }
            if fits2 {
                fit_r2 = true;
            }
            if not_fit_r1 && fit_r2 {
                break;
            }
        }
        not_fit_r1 && fit_r2
    };

    // LIC 15
    cmv[14] = area1_ok && area2_ok && e_pts_ok && if numpoints < e_pts + f_pts + 3 {
        false
    } else {
        let mut gt = false;
        let mut lt = false;
        for i in 0..=numpoints - e_pts - f_pts - 3 {
            let area = triangle_area(
                x_vals[i],
                y_vals[i],
                x_vals[i + e_pts + 1],
                y_vals[i + e_pts + 1],
                x_vals[i + e_pts + f_pts + 2],
                y_vals[i + e_pts + f_pts + 2],
            );
            if realcompare(area, area1) == Comp::GT {
                gt = true;
            }
            if realcompare(area, area2) == Comp::LT {
                lt = true;
            }
            if gt && lt {
                break;
            }
        }
        gt && lt
    };

    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        pum[i][i] = pum_diag[i];
        for j in 0..15 {
            if i == j {
                continue;
            }
            let lcm = as_str(&lcm_rows[i].as_arr()[j]);
            pum[i][j] = match lcm {
                "NOTUSED" => true,
                "ANDD" => cmv[i] && cmv[j],
                "ORR" => cmv[i] || cmv[j],
                _ => panic!("invalid LCM value"),
            };
        }
    }

    let mut fuv = vec![false; 15];
    for i in 0..15 {
        fuv[i] = !pum[i][i] || pum[i].iter().all(|&b| b);
    }
    let launch = fuv.iter().all(|&b| b);

    JsonValue::Obj(HashMap::from([
        ("cmv".to_string(), JsonValue::Arr(cmv.into_iter().map(JsonValue::Bool).collect())),
        (
            "pum".to_string(),
            JsonValue::Arr(
                pum.into_iter()
                    .map(|row| JsonValue::Arr(row.into_iter().map(JsonValue::Bool).collect()))
                    .collect(),
            ),
        ),
        ("fuv".to_string(), JsonValue::Arr(fuv.into_iter().map(JsonValue::Bool).collect())),
        ("launch".to_string(), JsonValue::Bool(launch)),
    ]))
}

trait ArrAccess {
    fn as_arr(&self) -> &[JsonValue];
}

impl ArrAccess for JsonValue {
    fn as_arr(&self) -> &[JsonValue] {
        as_arr(self)
    }
}

fn serialize(v: &JsonValue, out: &mut String) {
    match v {
        JsonValue::Null => out.push_str("null"),
        JsonValue::Bool(b) => out.push_str(if *b { "true" } else { "false" }),
        JsonValue::Num(n) => {
            if n.is_finite() {
                let mut s = format!("{}", n);
                if s.contains('.') {
                    while s.ends_with('0') {
                        s.pop();
                    }
                    if s.ends_with('.') {
                        s.push('0');
                    }
                }
                out.push_str(&s);
            } else {
                out.push_str("null");
            }
        }
        JsonValue::Str(s) => {
            out.push('"');
            for ch in s.chars() {
                match ch {
                    '"' => out.push_str("\\\""),
                    '\\' => out.push_str("\\\\"),
                    '\n' => out.push_str("\\n"),
                    '\r' => out.push_str("\\r"),
                    '\t' => out.push_str("\\t"),
                    '\u{0008}' => out.push_str("\\b"),
                    '\u{000C}' => out.push_str("\\f"),
                    c if c < ' ' => out.push_str(&format!("\\u{:04x}", c as u32)),
                    c => out.push(c),
                }
            }
            out.push('"');
        }
        JsonValue::Arr(items) => {
            out.push('[');
            let mut first = true;
            for item in items {
                if !first {
                    out.push(',');
                }
                first = false;
                serialize(item, out);
            }
            out.push(']');
        }
        JsonValue::Obj(map) => {
            out.push('{');
            let mut first = true;
            for key in ["cmv", "pum", "fuv", "launch"] {
                if let Some(v) = map.get(key) {
                    if !first {
                        out.push(',');
                    }
                    first = false;
                    serialize(&JsonValue::Str(key.to_string()), out);
                    out.push(':');
                    serialize(v, out);
                }
            }
            out.push('}');
        }
    }
}

fn main() {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();
    let parsed = Parser::new(&input).parse().unwrap();
    let output = solve(parsed);
    let mut s = String::new();
    serialize(&output, &mut s);
    print!("{}", s);
}
